package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bijzinderebijdrage.BijzondereBijdrageConstant;
import be.schaubroeck.lpb.rkm.rekenmotor.bijzinderebijdrage.BijzondereBijdrageCriterium;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.OpdrachtenGroepBuilder;
import be.schaubroeck.lpb.rkm.rekenmotor.util.OpdrachtenGroepBuilder.OpdrachtGroep;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.BijzBijdrage;
import be.schaubroeck.lpb.tools.enumtypes.Fiskgezinstoestand;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import com.google.common.collect.Sets;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_BIJZONDERE_BIJDRAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_OVERUREN_GECO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_RSZ_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_TAO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJZONDERE_BIJDRAGE_KEY;

@Slf4j
public class BerekenBijzondereBijdrage extends AbstractRekenCommand {

    public static final LocalDate IN_WERKING_TREDING = new LocalDate(1994, 4, 1);
    public static final LocalDate NIEUWE_SITUATIE = new LocalDate(2022, 4, 1);
    private static final Set<Fiskgezinstoestand> FISCALE_GEZINSTOESTAND_TYPE_A =
            Sets.immutableEnumSet(Fiskgezinstoestand.ALLEENSTAANDE, Fiskgezinstoestand.EGEENBPI, Fiskgezinstoestand.ELAAGPENS);

    private static final int AANTAL_SCHIJVEN = 7;
    private static final Konstanten[] ENUMS_GRENS =
            {Konstanten.BZBD_GRENS_1, Konstanten.BZBD_GRENS_2, Konstanten.BZBD_GRENS_3, Konstanten.BZBD_GRENS_4, Konstanten.BZBD_GRENS_5,
                    Konstanten.BZBD_GRENS_6};
    private final Money[] grens = new Money[AANTAL_SCHIJVEN];
    private final Money[] forfait = new Money[AANTAL_SCHIJVEN];
    private final BigDecimal[] percentage = new BigDecimal[AANTAL_SCHIJVEN];
    private final Money[] min = new Money[AANTAL_SCHIJVEN];
    private final Money[] max = new Money[AANTAL_SCHIJVEN];
    private final ConstantManager constantManager;

    public BerekenBijzondereBijdrage(ConstantManager constantManager) {
        this.constantManager = constantManager;
    }

    @Override
    protected boolean execute(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
        if (!rekenTijd.beginDatum.isBefore(IN_WERKING_TREDING)) {
            RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
            Persoon persoon = context.getUnchecked(PERSOON_KEY);
            loadConstants(persoon, rekenTijd);

            LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
            OpdrachtenGroepBuilder groeper = new OpdrachtenGroepBuilder();
            OpdrachtGroepCriterium criterium = new BijzondereBijdrageCriterium();
            List<OpdrachtGroep> opdrachtGroepen = groeper.groepeer(persoon, criterium, rekenTijd);
            for (OpdrachtGroep groep : opdrachtGroepen) {
                if (komtInAanmerkingBijzondereBijdrage(groep)) {
                    berekenBijzondereBijdrage(manager, groep, regulManager);
                }
            }
            Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
            Money bijzondereBijdrage = RekenTools.getSomProperty(BIJZONDERE_BIJDRAGE_KEY, loonElementen);
            context.put(BIJZONDERE_BIJDRAGE_KEY, bijzondereBijdrage);
        }

        return CONTINUE_PROCESSING;
    }

    public boolean komtInAanmerkingBijzondereBijdrage(OpdrachtGroep groep) {
        return groep.getSleutel() != 0;
    }

    private void berekenBijzondereBijdrage(LoonElementManager manager, OpdrachtGroep groep, RegulManager regulManager) {
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(groep.getOpdrachten());
        Money totaalBasis = vormBasis(loonElementen);
        Money bijzondereBijdrage = bepaalBijzondereBijdrageRsz(groep, totaalBasis, regulManager);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(BIJZONDERE_BIJDRAGE_KEY, bijzondereBijdrage, BASIS_BIJZONDERE_BIJDRAGE_KEY, totaalBasis, loonElementen);
        //nog eens herverdelen per opdacht noodzakelijk voor consistentie bij overdragen bij achterstal
        for (Opdracht opdracht : groep.getOpdrachten()) {
            Collection<LoonElement> opdrachtsElementen = manager.getOpdrachtsElementen(opdracht);
            Money bijzondereBijdrageOpdracht = RekenTools.getSomProperty(BIJZONDERE_BIJDRAGE_KEY, opdrachtsElementen);
            Money basisBijzondereBijdrage = RekenTools.getSomProperty(BASIS_BIJZONDERE_BIJDRAGE_KEY, opdrachtsElementen);
            if (basisBijzondereBijdrage.signum() != 0) {
                BedragVerdelerFactory.verdeelBedragVolgensBasisPut(BIJZONDERE_BIJDRAGE_KEY, bijzondereBijdrageOpdracht, BASIS_BIJZONDERE_BIJDRAGE_KEY,
                        basisBijzondereBijdrage, opdrachtsElementen);
            }
        }
    }

    public Money vormBasis(Collection<LoonElement> loonElementen) {
        Money totaalBasis = Money.ZERO;
        for (LoonElement element : loonElementen) {
            Money basis = element.getPropertyMoney(BASIS_RSZ_KEY);
            basis = basis.add(element.getPropertyMoney(BASIS_TAO_KEY));
            basis = basis.add(element.getPropertyMoney(BASIS_OVERUREN_GECO_KEY));
            element.putProperty(BASIS_BIJZONDERE_BIJDRAGE_KEY, basis);
            totaalBasis = totaalBasis.add(basis);
        }
        return totaalBasis;
    }

    private Money bepaalBijzondereBijdrageRsz(OpdrachtGroep groep, Money basis, RegulManager regulManager) {
        BijzBijdrage bijzondereBijdrageWerkwijze = BijzBijdrage.getByCode(groep.getSleutel());
        Money bijzondereBijdrageRsz = Money.ZERO;
        switch (bijzondereBijdrageWerkwijze) {
            case BAREMA:
                int grensnr = 0;
                while ((grensnr < (AANTAL_SCHIJVEN - 1)) && basis.compareTo(grens[grensnr + 1]) > 0) {
                    grensnr++;
                }
                bijzondereBijdrageRsz =
                        schijfBijzondereBijdrage(basis, grens[grensnr], forfait[grensnr], percentage[grensnr], min[grensnr], max[grensnr]);
                break;
            case SCHIJF_1:
            case SCHIJF_2:
            case SCHIJF_3:
            case SCHIJF_4:
            case SCHIJF_5:
            case SCHIJF_6:
                bijzondereBijdrageRsz = forfait[bijzondereBijdrageWerkwijze.getCode() - 2];
                break;
            case GEEN_INH:
                break;
            default:
                regulManager.doRegulException(null, Regulkode.ONGELDIGE_KODE_BIJZBIJDRAGE);
                break;
        }
        return bijzondereBijdrageRsz.round(2);
    }

    private Money schijfBijzondereBijdrage(Money basis, Money grens, Money forfait, BigDecimal percentage, Money min, Money max) {
        Money schijf = forfait.add(basis.subtract(grens).multiply(percentage));
        schijf = schijf.max(min);
        schijf = schijf.min(max);
        return schijf;
    }

    private void loadConstants(Persoon persoon, RekenTijd rekenTijd) {
        PersoonsFiscaliteit persoonsFiscaliteit = RekenTools.getPersoonsFiscaliteitLaatsteGegevens(persoon);
        Fiskgezinstoestand fiscaleGezinsToestand = persoonsFiscaliteit.getFiscaleGezinsToestand();
        grens[0] = Money.ZERO;
        for (int index = 1; index < AANTAL_SCHIJVEN; index++) {
            grens[index] = constantManager.getActualConstant(ENUMS_GRENS[index - 1], rekenTijd).getMoney();
        }

        BijzondereBijdrageConstant constants = bepaalBijzondereBijdrageConstant(rekenTijd, fiscaleGezinsToestand);

        for (int index = 0; index < AANTAL_SCHIJVEN; index++) {
            forfait[index] = constantManager.getActualConstant(constants.getEnumsForfait()[index], rekenTijd).getMoney();
            percentage[index] = constantManager.getActualConstant(constants.getEnumsPercentage()[index], rekenTijd).getProcentFactor();
            min[index] = constantManager.getActualConstant(constants.getEnumsMin()[index], rekenTijd).getMoney();
            max[index] = constantManager.getActualConstant(constants.getEnumsMax()[index], rekenTijd).getMoney();
        }
    }

    public BijzondereBijdrageConstant bepaalBijzondereBijdrageConstant(RekenTijd rekenTijd, Fiskgezinstoestand fiscaleGezinsToestand) {
        if (rekenTijd.beginDatum.isBefore(NIEUWE_SITUATIE)) {
            boolean type = FISCALE_GEZINSTOESTAND_TYPE_A.contains(fiscaleGezinsToestand);
            return type ? BijzondereBijdrageConstant.bijzondereBijdrageConstantTypeA() : BijzondereBijdrageConstant.bijzondereBijdrageConstantTypeB();
        } else {
            return bepaalBijzondereBijdrageConstantNa01042022(fiscaleGezinsToestand);
        }
    }

    private BijzondereBijdrageConstant bepaalBijzondereBijdrageConstantNa01042022(Fiskgezinstoestand fiscaleGezinsToestand) {
        if (fiscaleGezinsToestand == Fiskgezinstoestand.ALLEENSTAANDE) {
            return BijzondereBijdrageConstant.bijzondereBijdrageConstantTypeA();
        } else if (laagOfGeenBeroepsInkomsten(fiscaleGezinsToestand)) {
            return BijzondereBijdrageConstant.bijzondereBijdrageConstantTypeC();
        } else {
            return BijzondereBijdrageConstant.bijzondereBijdrageConstantTypeB();
        }
    }

    private boolean laagOfGeenBeroepsInkomsten(Fiskgezinstoestand fiscaleGezinsToestand) {
        return fiscaleGezinsToestand == Fiskgezinstoestand.EGEENBPI || fiscaleGezinsToestand == Fiskgezinstoestand.ELAAGBPI ||
                fiscaleGezinsToestand == Fiskgezinstoestand.ELAAGPENS;
    }

}
